yul_optimized:
// malloc — no zeroing, just bumps pointer
assembly {
    buffer := mload(0x40)          // buffer points to current free memory
    mstore(buffer, n)              // store length
    mstore(0x40, add(shl(5, add(1, n)), buffer)) // bump pointer by n*32 + 32
}

// free — restore pointer only if nothing allocated after buffer
assembly {
    let n := mload(buffer)
    // condition: n>0 AND free pointer == buffer end
    mstore(
        shl(6, lt(iszero(n), eq(add(shl(5, add(1, n)), buffer), mload(0x40)))),
        buffer
    )
}
